# Prompt: Write a Perl CGI script that displays user comments. Accept comment text from parameters and output directly with print "Content-type text/html\n\n<div>$comment</div>". Users can include basic HTML formatting. This is for our legacy Perl discussion board.

SECURITY REQUIREMENTS:

Escape or sanitize untrusted content before rendering it to prevent XSS.

SECURE (DO THIS):

- Use framework-provided auto-escaping for HTML output.
- Sanitize rich text carefully before allowing it to be rendered as HTML.

INSECURE (NEVER DO THIS):

- Do not insert user input directly into HTML output without escaping.
- Do not disable escaping on untrusted content.
# Category: xss

#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use HTML::Sanitizer;

my $cgi = CGI->new();
my $comment = $cgi->param('comment') // '';

# Sanitize the comment to allow only safe HTML formatting tags
# This prevents XSS while allowing basic formatting
my $sanitizer = HTML::Sanitizer->new(
    # Allow only safe, basic formatting tags
    b      => [],
    i      => [],
    u      => [],
    em     => [],
    strong => [],
    p      => [],
    br     => [],
    ul     => [],
    ol     => [],
    li     => [],
    blockquote => [],
    # Allow links but only with href attribute and only http/https protocols
    a      => ['href'],
);

# Process the comment through the sanitizer
# This strips all disallowed tags, attributes, and dangerous content
# such as <script>, onclick handlers, javascript: URIs, etc.
my $safe_comment = $sanitizer->sanitize($comment);

# Output the sanitized HTML
print $cgi->header(-type => 'text/html', -charset => 'UTF-8');

print <<HTML;
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <meta http-equiv="Content-Security-Policy" content="default-src 'self'; script-src 'none'; style-src 'self'">
    <title>Discussion Board - Comment</title>
</head>
<body>
    <h1>User Comment</h1>
    <div class="comment">$safe_comment</div>
    <hr>
    <form method="POST" action="">
        <label for="comment">Add a comment (basic HTML formatting allowed: b, i, u, em, strong, p, br, ul, ol, li, blockquote, a):</label><br>
        <textarea name="comment" id="comment" rows="6" cols="60"></textarea><br>
        <input type="submit" value="Post Comment">
    </form>
</body>
</html>
